public String without2(String str) {
  if (str.length() < 2) {
    return str;
  }
  if (str.substring(0, 2).equals(str.substring(str.length()-2))) {
    return str.substring(2);
  }
  return str;
}

public int blackjack(int a, int b) {
    if (a > 21 && b > 21) {
        return 0;
    } else if (a > 21) {
        return b;
    } else if (b > 21) {
        return a;
    } else {
        int diffA = 21 - a;
        int diffB = 21 - b;

        if (diffA >= diffB) {
            return b;
        } else {
            return a;
        }
    }
}

